// D1 has one flat schema (no multi-schema/RLS concept like Postgres), so
// these no longer need the schema-option overload the Supabase CLI
// generates -- just index straight into Database["Tables"].
export type Tables<TableName extends keyof Database["Tables"]> =
  Database["Tables"][TableName]["Row"];

export type TablesInsert<TableName extends keyof Database["Tables"]> =
  Database["Tables"][TableName]["Insert"];

export type TablesUpdate<TableName extends keyof Database["Tables"]> =
  Database["Tables"][TableName]["Update"];

